def _format_feet_mm(value_ft):
    try:
        value_ft = float(value_ft)
        return "{0:.3f} ft ({1:.0f} mm)".format(value_ft, value_ft * 304.8)
    except:
        return "unreadable"


def _format_xyz_feet(vector):
    try:
        x, y, z = _xyz_components(vector)
        return "({0:.6f}, {1:.6f}, {2:.6f})".format(float(x), float(y), float(z))
    except:
        return "(unreadable)"


def _format_xyz_mm(vector):
    try:
        x, y, z = _xyz_components(vector)
        return "({0:.0f}, {1:.0f}, {2:.0f})".format(float(x) * 304.8, float(y) * 304.8, float(z) * 304.8)
    except:
        return "(unreadable)"


def _xyz_mm_plain(vector):
    plain = _xyz_plain(vector)
    if not plain:
        return None
    try:
        return [float(plain[0]) * 304.8, float(plain[1]) * 304.8, float(plain[2]) * 304.8]
    except:
        return None


def _transform_basis_vector_text(vector):
    try:
        return "({0:.6f}, {1:.6f}, {2:.6f})".format(float(vector.X), float(vector.Y), float(vector.Z))
    except:
        return "unreadable"


def _transform_basis_determinant(transform):
    try:
        bx = transform.BasisX
        by = transform.BasisY
        bz = transform.BasisZ
        return (
            float(bx.X) * (float(by.Y) * float(bz.Z) - float(by.Z) * float(bz.Y))
            - float(by.X) * (float(bx.Y) * float(bz.Z) - float(bx.Z) * float(bz.Y))
            + float(bz.X) * (float(bx.Y) * float(by.Z) - float(bx.Z) * float(by.Y))
        )
    except:
        return None


def _link_transform_workset_name(doc, elem):
    try:
        workset_id = getattr(elem, "WorksetId", None)
        if workset_id is None:
            return "unreadable"
        table = doc.GetWorksetTable()
        if table is None:
            return "unreadable"
        workset = table.GetWorkset(workset_id)
        name = getattr(workset, "Name", None)
        return safe_str(name) if name else "unreadable"
    except:
        return "unreadable"


def _link_transform_design_option_name(doc, elem):
    try:
        option_id = getattr(elem, "DesignOption", None)
        if option_id is not None:
            name = get_elem_name(option_id)
            if name:
                return name
        option_id = getattr(elem, "DesignOptionId", None)
        if option_id is None:
            return "none"
        if option_id == DB.ElementId.InvalidElementId:
            return "none"
        option = doc.GetElement(option_id)
        name = get_elem_name(option)
        return name if name else "none"
    except:
        return "unreadable"


def _link_transform_grouped(elem):
    try:
        group_id = getattr(elem, "GroupId", None)
        if group_id is None:
            return False
        return group_id != DB.ElementId.InvalidElementId
    except:
        return False


def _link_transform_type_info(doc, instance):
    link_type = None
    try:
        link_type = doc.GetElement(instance.GetTypeId())
    except:
        link_type = None
    type_id = _safe_element_id_value(link_type) if link_type is not None else None
    type_name = get_elem_name(link_type) if link_type is not None else "unreadable"
    return link_type, type_id, type_name


def _collect_link_transform_audit_data(doc, uidoc=None, prompt="audit link transforms"):
    selected_link_ids = set()
    try:
        for elem in _selected_elements(doc, uidoc):
            try:
                if isinstance(elem, DB.RevitLinkInstance):
                    selected_link_ids.add(int(elem.Id.IntegerValue))
            except:
                pass
    except:
        pass

    links = []
    try:
        instances = list(DB.FilteredElementCollector(doc).OfClass(DB.RevitLinkInstance))
    except:
        instances = []
    try:
        instances = sorted(instances, key=lambda item: (_safe_element_id_value(item) or 0, safe_str(get_elem_name(item))))
    except:
        pass

    for index, instance in enumerate(instances, start=1):
        instance_id = _safe_element_id_value(instance)
        instance_name = get_elem_name(instance) or "(unnamed link instance)"
        link_type, type_id, type_name = _link_transform_type_info(doc, instance)
        linked_document_title = "unreadable"
        linked_document_readable = False
        try:
            link_doc = instance.GetLinkDocument()
            if link_doc is not None:
                linked_document_readable = True
                linked_document_title = _document_title(link_doc)
            else:
                linked_document_title = "unloaded or unresolved"
        except:
            linked_document_title = "unreadable"

        pinned = _safe_bool_attr(instance, "Pinned")
        grouped = _link_transform_grouped(instance)
        workset_name = _link_transform_workset_name(doc, instance)
        design_option_name = _link_transform_design_option_name(doc, instance)
        restricted = design_option_name not in ("none", "unreadable", "")
        transform = None
        transform_readable = False
        origin = None
        distance = None
        rotation_z = "unreadable"
        basis_x = "unreadable"
        basis_y = "unreadable"
        basis_z = "unreadable"
        basis_orthonormal = "unknown"
        mirrored = "unreadable"
        try:
            transform = instance.GetTransform()
            transform_readable = True
            origin = transform.Origin
            distance = math.sqrt(float(origin.X) ** 2 + float(origin.Y) ** 2 + float(origin.Z) ** 2)
            rotation_z = _transform_rotation_z_degrees(transform)
            basis_x = _transform_basis_vector_text(transform.BasisX)
            basis_y = _transform_basis_vector_text(transform.BasisY)
            basis_z = _transform_basis_vector_text(transform.BasisZ)
            basis_orthonormal = _basis_appears_orthonormal(transform)
            determinant = _transform_basis_determinant(transform)
            if determinant is not None:
                mirrored = determinant < 0.0
        except:
            transform_readable = False

        near_zero = bool(distance is not None and distance <= LINK_TRANSFORM_ZERO_ORIGIN_TOLERANCE_FT)
        rotated = False
        try:
            angle = abs(float(rotation_z))
            angle = min(angle, abs(360.0 - angle))
            rotated = angle > LINK_TRANSFORM_ROTATION_TOLERANCE_DEG
        except:
            rotated = False
        nonorthogonal = basis_orthonormal not in (True, "unknown")
        caution_reasons = []
        if not linked_document_readable or not transform_readable:
            caution_reasons.append("Linked document or transform is unloaded/unreadable.")
        if distance is not None and not near_zero:
            caution_reasons.append("Link origin is outside the zero-origin tolerance.")
        if rotated or nonorthogonal:
            caution_reasons.append("Link transform is rotated or basis is non-orthonormal.")
        if pinned:
            caution_reasons.append("Link is pinned.")
        if grouped:
            caution_reasons.append("Link is grouped.")
        if restricted:
            caution_reasons.append("Link is in a design option or restricted context.")

        classifications = []
        if not linked_document_readable or not transform_readable:
            classifications.append("UNLOADED_OR_UNREADABLE")
        elif pinned:
            classifications.append("PINNED_LINK")
        elif grouped or restricted:
            classifications.append("GROUPED_OR_RESTRICTED")
        elif rotated or nonorthogonal:
            classifications.append("ROTATED_OR_NONORTHOGONAL")
        elif not near_zero:
            classifications.append("OFFSET_FROM_ZERO")
        else:
            classifications.append("OK_ZERO_ORIGIN")
        if caution_reasons and "REVIEW_REQUIRED" not in classifications:
            classifications.append("REVIEW_REQUIRED")

        future_reset_candidate = bool(
            linked_document_readable
            and transform_readable
            and not pinned
            and not grouped
            and not restricted
            and distance is not None
            and not near_zero
        )
        links.append(
            {
                "index": index,
                "instance_id": instance_id,
                "instance_name": instance_name,
                "type_id": type_id,
                "type_name": type_name,
                "linked_document_title": linked_document_title,
                "linked_document_readable": linked_document_readable,
                "pinned": bool(pinned),
                "grouped": bool(grouped),
                "workset_name": workset_name,
                "design_option_name": design_option_name,
                "transform_source": "GetTransform",
                "transform_readable": transform_readable,
                "origin_feet": _format_xyz_feet(origin),
                "origin_mm": _format_xyz_mm(origin),
                "distance_from_zero": distance,
                "rotation_z_degrees": rotation_z,
                "basis_x": basis_x,
                "basis_y": basis_y,
                "basis_z": basis_z,
                "mirrored": mirrored,
                "near_zero_origin": near_zero,
                "rotated_or_nonorthogonal": bool(rotated or nonorthogonal),
                "classification": ", ".join(classifications),
                "future_reset_candidate": future_reset_candidate,
                "caution_reasons": caution_reasons,
                "selected": instance_id in selected_link_ids,
            }
        )

    loaded_count = len([item for item in links if item.get("linked_document_readable")])
    unreadable_count = len([item for item in links if not item.get("linked_document_readable") or not item.get("transform_readable")])
    near_zero_count = len([item for item in links if item.get("near_zero_origin")])
    offset_count = len([item for item in links if item.get("distance_from_zero") is not None and not item.get("near_zero_origin")])
    rotated_count = len([item for item in links if item.get("rotated_or_nonorthogonal")])
    pinned_count = len([item for item in links if item.get("pinned")])
    reset_candidate_count = len([item for item in links if item.get("future_reset_candidate")])
    review_count = len([item for item in links if item.get("caution_reasons")])
    if not links:
        audit_result = "No links found"
        recommendation = "load/link models before running link transform audit"
    elif unreadable_count:
        audit_result = "Review required"
        recommendation = "reload/resolve links before reset review"
    elif pinned_count:
        audit_result = "Review required"
        recommendation = "manually review pinned/restricted links before future reset"
    elif offset_count or rotated_count:
        audit_result = "Review required"
        recommendation = "review offset links and run future rollback test/reset feature when implemented"
    else:
        audit_result = "OK"
        recommendation = "no coordinate action required"
    return {
        "feature_id": "COORD-WR-001",
        "feature_name": "Link Transform Audit / Coordinate Drift Report",
        "audit_id": "COORD-WR-001-{0}".format(time.strftime("%Y%m%d_%H%M%S")),
        "source_prompt": safe_str(prompt),
        "created_timestamp_local": time.strftime("%Y-%m-%d %H:%M:%S"),
        "document_title": _document_title(doc),
        "active_view_name": _active_view_title(doc, uidoc),
        "active_view_type": safe_str(getattr(getattr(uidoc, "ActiveView", None), "ViewType", "(unknown type)")),
        "selected_link_ids": sorted(selected_link_ids),
        "links": links,
        "loaded_count": loaded_count,
        "unreadable_count": unreadable_count,
        "near_zero_count": near_zero_count,
        "offset_count": offset_count,
        "rotated_count": rotated_count,
        "pinned_count": pinned_count,
        "reset_candidate_count": reset_candidate_count,
        "review_count": review_count,
        "audit_result": audit_result,
        "recommended_next_action": recommendation,
    }


def _build_link_transform_audit_shared_state(data):
    links = data.get("links") or []
    selected_count = len([item for item in links if item.get("selected")])
    return {
        "feature_id": "COORD-WR-001",
        "audit_id": safe_str(data.get("audit_id")),
        "timestamp": safe_str(data.get("created_timestamp_local")),
        "created_timestamp_local": safe_str(data.get("created_timestamp_local")),
        "document_title": safe_str(data.get("document_title")),
        "active_view_name": safe_str(data.get("active_view_name")),
        "audit_result": safe_str(data.get("audit_result")),
        "total_link_count": len(links),
        "loaded_link_count": _safe_int(data.get("loaded_count"), 0),
        "unloaded_link_count": _safe_int(data.get("unreadable_count"), 0),
        "selected_revit_link_count": selected_count,
        "near_zero_count": _safe_int(data.get("near_zero_count"), 0),
        "offset_count": _safe_int(data.get("offset_count"), 0),
        "rotated_nonorthogonal_count": _safe_int(data.get("rotated_count"), 0),
        "pinned_count": _safe_int(data.get("pinned_count"), 0),
        "future_reset_candidate_count": _safe_int(data.get("reset_candidate_count"), 0),
        "manual_review_count": _safe_int(data.get("review_count"), 0),
        "zero_origin_tolerance_ft": float(LINK_TRANSFORM_ZERO_ORIGIN_TOLERANCE_FT),
        "model_modified": False,
        "transaction_opened": False,
    }


def _format_link_transform_audit_report(data):
    links = data.get("links") or []
    selected_links = [item for item in links if item.get("selected")]
    lines = [
        "[LINK TRANSFORM AUDIT REPORT]",
        "",
        "Feature ID:",
        "COORD-WR-001",
        "",
        "Feature name:",
        "Link Transform Audit / Coordinate Drift Report",
        "",
        "Audit ID:",
        data.get("audit_id"),
        "",
        "Active document:",
        data.get("document_title"),
        "",
        "Active view:",
        "{0} [{1}]".format(data.get("active_view_name"), data.get("active_view_type")),
        "",
        "Scope:",
        "active document Revit link transform audit / read-only",
        "",
        "Summary:",
        "- Total Revit link instances found: {0}".format(len(links)),
        "- Loaded link instances: {0}".format(data.get("loaded_count")),
        "- Unloaded / unresolved link instances: {0}".format(data.get("unreadable_count")),
        "- Selected Revit link instances: {0}".format(len(selected_links)),
        "- Links near zero origin: {0}".format(data.get("near_zero_count")),
        "- Links offset from zero: {0}".format(data.get("offset_count")),
        "- Links rotated/non-orthogonal: {0}".format(data.get("rotated_count")),
        "- Links pinned: {0}".format(data.get("pinned_count")),
        "- Future reset candidates: {0}".format(data.get("reset_candidate_count")),
        "- Links requiring manual review: {0}".format(data.get("review_count")),
        "- Zero-origin tolerance: {0}".format(_format_feet_mm(LINK_TRANSFORM_ZERO_ORIGIN_TOLERANCE_FT)),
        "",
        "Selected links:",
    ]
    if selected_links:
        for item in selected_links:
            lines.append("- {0} | {1}".format(item.get("instance_id"), item.get("instance_name")))
    else:
        lines.append("- none")
    lines.extend(["", "Link transform audit:"])
    if not links:
        lines.append("- No RevitLinkInstance elements found in the active document.")
    for item in links:
        lines.extend(
            [
                "",
                "Link instance {0}:".format(item.get("index")),
                "- Link instance element id: {0}".format(item.get("instance_id")),
                "- Link instance name: {0}".format(item.get("instance_name")),
                "- Link type id: {0}".format(item.get("type_id")),
                "- Link type name: {0}".format(item.get("type_name")),
                "- Linked document title: {0}".format(item.get("linked_document_title")),
                "- Is loaded / linked document readable: {0}".format("true" if item.get("linked_document_readable") else "false"),
                "- Is pinned: {0}".format("true" if item.get("pinned") else "false"),
                "- Is grouped: {0}".format("true" if item.get("grouped") else "false"),
                "- Workset name: {0}".format(item.get("workset_name")),
                "- Design option name: {0}".format(item.get("design_option_name")),
                "- Transform source used: {0}".format(item.get("transform_source")),
                "- Origin XYZ internal feet: {0}".format(item.get("origin_feet")),
                "- Origin XYZ approximate mm: {0}".format(item.get("origin_mm")),
                "- Distance from zero: {0}".format(_format_feet_mm(item.get("distance_from_zero"))),
                "- Rotation about Z: {0}".format(
                    "{0:.4f} degrees".format(float(item.get("rotation_z_degrees")))
                    if isinstance(item.get("rotation_z_degrees"), (int, float))
                    else safe_str(item.get("rotation_z_degrees"))
                ),
                "- BasisX vector: {0}".format(item.get("basis_x")),
                "- BasisY vector: {0}".format(item.get("basis_y")),
                "- BasisZ vector: {0}".format(item.get("basis_z")),
                "- Is mirrored: {0}".format(safe_str(item.get("mirrored")).lower()),
                "- Is near zero origin: {0}".format("true" if item.get("near_zero_origin") else "false"),
                "- Coordinate drift classification: {0}".format(item.get("classification")),
                "- Candidate for future reviewed reset: {0}".format("true" if item.get("future_reset_candidate") else "false"),
                "- Blocking / caution reasons for future reset: {0}".format(
                    "; ".join(item.get("caution_reasons") or ["none"])
                ),
            ]
        )
    lines.extend(
        [
            "",
            "Audit result:",
            data.get("audit_result"),
            "",
            "Recommended next action:",
            data.get("recommended_next_action"),
            "",
            "Execution status:",
            "- Audit requested: true",
            "- Transaction opened: false",
            "- Link transform modified: false",
            "- Model modified: false",
            "- UI selection modified: false",
            "",
            "Safety:",
            "- Read-only audit only.",
            "- No Transaction opened.",
            "- No link was moved.",
            "- No link was rotated.",
            "- No link was pinned/unpinned.",
            "- No Revit model data was modified.",
            "- No linked documents were modified.",
            "- No reload/unload was performed.",
        ]
    )
    return "\n".join(lines)


def _xyz_distance(a, b):
    try:
        ax, ay, az = _xyz_components(a)
        bx, by, bz = _xyz_components(b)
        dx = float(ax) - float(bx)
        dy = float(ay) - float(by)
        dz = float(az) - float(bz)
        return math.sqrt(dx * dx + dy * dy + dz * dz)
    except:
        return None


def _basis_vectors_from_transform_or_plain(value):
    try:
        return [value.BasisX, value.BasisY, value.BasisZ]
    except:
        pass
    try:
        if isinstance(value, dict):
            return [value.get("basis_x"), value.get("basis_y"), value.get("basis_z")]
    except:
        pass
    return None


def _transform_basis_matches(a, b):
    try:
        left_vectors = _basis_vectors_from_transform_or_plain(a)
        right_vectors = _basis_vectors_from_transform_or_plain(b)
        if not left_vectors or not right_vectors:
            return "unknown"
        pairs = zip(left_vectors, right_vectors)
        for left, right in pairs:
            distance = _xyz_distance(left, right)
            if distance is None or distance > LINK_TRANSFORM_BASIS_TOLERANCE:
                return False
        return True
    except:
        return "unknown"


def _link_origin_rotation_blocked(rotation_z):
    try:
        angle = abs(float(rotation_z))
        angle = min(angle, abs(360.0 - angle))
        return angle > LINK_TRANSFORM_ROTATION_TOLERANCE_DEG
    except:
        return True


def _coord_link_selected_context(doc, uidoc, prompt, token_present, rollback_requested):
    selected_elements = []
    selected_links = []
    try:
        selected_elements = _selected_elements(doc, uidoc)
    except:
        selected_elements = []
    for elem in selected_elements:
        try:
            if isinstance(elem, DB.RevitLinkInstance):
                selected_links.append(elem)
        except:
            pass

    data = {
        "feature_id": "COORD-WR-002",
        "feature_name": "Link Origin Reset Rollback Test",
        "rollback_test_id": "COORD-WR-002-{0}".format(time.strftime("%Y%m%d_%H%M%S")),
        "source_prompt": safe_str(prompt),
        "created_timestamp_local": time.strftime("%Y-%m-%d %H:%M:%S"),
        "document_title": _document_title(doc),
        "active_view_name": _active_view_title(doc, uidoc),
        "active_view_type": safe_str(getattr(getattr(uidoc, "ActiveView", None), "ViewType", "(unknown type)")),
        "selected_element_count": len(selected_elements),
        "selected_link_count": len(selected_links),
        "confirmation_token_provided": bool(token_present),
        "rollback_test_requested": bool(rollback_requested),
        "confirmation_token_accepted": bool(token_present and rollback_requested),
        "blocking_reasons": [],
        "caution_reasons": [],
        "transaction_group_opened": False,
        "transaction_opened": False,
        "moveelement_called": False,
        "transaction_committed_inside_group": False,
        "transaction_group_rolled_back": False,
        "transaction_group_assimilated": False,
        "persistent_model_changes": False,
        "link_transform_modified_persistently": False,
        "ui_selection_modified": False,
        "linked_document_modified": False,
        "temporary_verification_passed": False,
        "final_origin_matches_original": False,
        "final_transform_basis_matches_original": "unknown",
        "rollback_test_result": "Not ready",
    }
    if len(selected_links) == 0:
        data["blocking_reasons"].append("Select exactly one Revit link instance.")
    elif len(selected_links) > 1:
        data["blocking_reasons"].append("Multiple Revit link instances are selected. Select only one Revit link instance.")
    selected_link = selected_links[0] if len(selected_links) == 1 else None
    if selected_link is None:
        return data

    link_type, type_id, type_name = _link_transform_type_info(doc, selected_link)
    linked_document_title = "unreadable"
    linked_document_readable = False
    try:
        link_doc = selected_link.GetLinkDocument()
        if link_doc is not None:
            linked_document_readable = True
            linked_document_title = _document_title(link_doc)
        else:
            linked_document_title = "unloaded or unresolved"
    except:
        linked_document_title = "unreadable"
    transform = None
    origin = None
    original_distance = None
    rotation_z = "unreadable"
    basis_x = "unreadable"
    basis_y = "unreadable"
    basis_z = "unreadable"
    mirrored = "unreadable"
    basis_orthonormal = "unknown"
    try:
        transform = selected_link.GetTransform()
        origin = transform.Origin
        original_distance = math.sqrt(float(origin.X) ** 2 + float(origin.Y) ** 2 + float(origin.Z) ** 2)
        rotation_z = _transform_rotation_z_degrees(transform)
        basis_x = _transform_basis_vector_text(transform.BasisX)
        basis_y = _transform_basis_vector_text(transform.BasisY)
        basis_z = _transform_basis_vector_text(transform.BasisZ)
        basis_orthonormal = _basis_appears_orthonormal(transform)
        determinant = _transform_basis_determinant(transform)
        if determinant is not None:
            mirrored = determinant < 0.0
    except:
        data["blocking_reasons"].append("Selected link transform is unreadable.")

    pinned = _safe_bool_attr(selected_link, "Pinned")
    grouped = _link_transform_grouped(selected_link)
    design_option_name = _link_transform_design_option_name(doc, selected_link)
    restricted = design_option_name not in ("none", "unreadable", "")
    near_zero = bool(original_distance is not None and original_distance <= LINK_TRANSFORM_ZERO_ORIGIN_TOLERANCE_FT)
    rotated = _link_origin_rotation_blocked(rotation_z)
    nonorthogonal = basis_orthonormal not in (True, "unknown")
    data.update(
        {
            "selected_link_element_id": _safe_element_id_value(selected_link),
            "selected_link_name": get_elem_name(selected_link) or "(unnamed link instance)",
            "link_type_id": type_id,
            "link_type_name": type_name,
            "linked_document_title": linked_document_title,
            "linked_document_readable": bool(linked_document_readable),
            "is_pinned": bool(pinned),
            "is_grouped": bool(grouped),
            "workset_name": _link_transform_workset_name(doc, selected_link),
            "design_option_name": design_option_name,
            "transform_source": "GetTransform",
            "original_transform": transform,
            "original_origin": origin,
            "original_origin_feet": _format_xyz_feet(origin),
            "original_origin_mm": _format_xyz_mm(origin),
            "original_distance_from_zero": original_distance,
            "original_rotation_z_degrees": rotation_z,
            "original_basis_x": basis_x,
            "original_basis_y": basis_y,
            "original_basis_z": basis_z,
            "original_mirrored": mirrored,
            "near_zero_before_test": near_zero,
            "coordinate_drift_classification_before_test": "OK_ZERO_ORIGIN" if near_zero else "OFFSET_FROM_ZERO",
            "translation_delta": DB.XYZ(-float(origin.X), -float(origin.Y), -float(origin.Z)) if origin is not None else None,
        }
    )
    if not linked_document_readable:
        data["blocking_reasons"].append("Linked document is unloaded or unreadable.")
    if pinned is True:
        data["blocking_reasons"].append("Selected link is pinned.")
    if grouped:
        data["blocking_reasons"].append("Selected link is grouped.")
    if restricted:
        data["blocking_reasons"].append("Selected link is in a design option or restricted context.")
    if rotated or nonorthogonal:
        data["blocking_reasons"].append("Selected link is rotated, mirrored, or non-orthonormal; COORD-WR-002 tests translation only.")
    if mirrored is True:
        data["blocking_reasons"].append("Selected link appears mirrored; COORD-WR-002 tests translation only.")
    if not rollback_requested:
        data["caution_reasons"].append("Status/readiness route only; rollback mutation test was not requested.")
    elif not token_present:
        data["blocking_reasons"].append("Missing confirmation token ROLLBACK-LINK-RESET-OK.")
    return data


def _coord_link_rollback_recommendation(data):
    reasons = " ".join(data.get("blocking_reasons") or []).lower()
    if data.get("rollback_test_result") == "Already at zero":
        return "no coordinate reset required"
    if data.get("rollback_test_result") == "Passed":
        return "future persistent reviewed reset may be implemented as COORD-WR-003"
    if data.get("rollback_test_result") == "Failed":
        return "do not implement persistent reset until failure is analyzed"
    if "missing confirmation token" in reasons:
        return "rerun with ROLLBACK-LINK-RESET-OK confirmation token"
    if "multiple" in reasons:
        return "select only one Revit link instance"
    if "pinned" in reasons:
        return "unpin manually only if approved by coordinator, then rerun rollback test"
    if "group" in reasons or "restricted" in reasons or "design option" in reasons:
        return "review group/restriction manually before reset"
    return "select exactly one Revit link instance"


def _run_link_origin_reset_rollback_test(doc, uidoc, prompt, rollback_requested=True, token_present=False):
    data = _coord_link_selected_context(doc, uidoc, prompt, token_present, rollback_requested)
    if data.get("blocking_reasons"):
        data["rollback_test_result"] = "Not ready"
        data["recommended_next_action"] = _coord_link_rollback_recommendation(data)
        return data
    if data.get("near_zero_before_test"):
        data["rollback_test_result"] = "Already at zero"
        data["recommended_next_action"] = _coord_link_rollback_recommendation(data)
        return data
    if not rollback_requested:
        data["rollback_test_result"] = "Not ready"
        data["recommended_next_action"] = _coord_link_rollback_recommendation(data)
        return data

    origin = data.get("original_origin")
    delta = data.get("translation_delta")
    link_id = None
    try:
        link_id = DB.ElementId(int(data.get("selected_link_element_id")))
    except:
        link_id = None
    if origin is None or delta is None or link_id is None:
        data["rollback_test_result"] = "Not ready"
        data["blocking_reasons"].append("Selected link origin or element id is unavailable.")
        data["recommended_next_action"] = _coord_link_rollback_recommendation(data)
        return data

    group = None
    transaction = None
    rollback_attempted = False
    try:
        group = DB.TransactionGroup(doc, "COORD-WR-002 Link Origin Reset Rollback Test")
        group.Start()
        data["transaction_group_opened"] = True
        transaction = DB.Transaction(doc, "Temporary link origin reset to zero")
        transaction.Start()
        data["transaction_opened"] = True
        DB.ElementTransformUtils.MoveElement(doc, link_id, delta)
        data["moveelement_called"] = True
        try:
            doc.Regenerate()
        except:
            pass
        link_after_move = doc.GetElement(link_id)
        temporary_transform = link_after_move.GetTransform()
        temporary_origin = temporary_transform.Origin
        temporary_distance = math.sqrt(float(temporary_origin.X) ** 2 + float(temporary_origin.Y) ** 2 + float(temporary_origin.Z) ** 2)
        data["temporary_origin"] = temporary_origin
        data["temporary_origin_feet"] = _format_xyz_feet(temporary_origin)
        data["temporary_origin_mm"] = _format_xyz_mm(temporary_origin)
        data["temporary_distance_from_zero"] = temporary_distance
        data["temporary_origin_near_zero"] = temporary_distance <= LINK_TRANSFORM_ZERO_ORIGIN_TOLERANCE_FT
        data["temporary_verification_passed"] = bool(data.get("temporary_origin_near_zero"))
        transaction.Commit()
        data["transaction_committed_inside_group"] = True
    except Exception as exc:
        data["rollback_test_result"] = "Failed"
        data["blocking_reasons"].append("Rollback move test failed: {0}".format(safe_str(exc)))
        try:
            if transaction is not None and data.get("transaction_opened") and not data.get("transaction_committed_inside_group"):
                transaction.RollBack()
        except:
            pass
    finally:
        if group is not None and data.get("transaction_group_opened"):
            try:
                rollback_attempted = True
                group.RollBack()
                data["transaction_group_rolled_back"] = True
            except Exception as rollback_exc:
                data["transaction_group_rolled_back"] = False
                data["blocking_reasons"].append("TransactionGroup rollback failed: {0}".format(safe_str(rollback_exc)))
    data["rollback_attempted"] = rollback_attempted

    try:
        final_link = doc.GetElement(link_id)
        final_transform = final_link.GetTransform()
        final_origin = final_transform.Origin
        distance_from_original = _xyz_distance(final_origin, origin)
        data["final_origin"] = final_origin
        data["final_origin_feet"] = _format_xyz_feet(final_origin)
        data["final_origin_mm"] = _format_xyz_mm(final_origin)
        data["final_distance_from_original"] = distance_from_original
        data["final_origin_matches_original"] = bool(distance_from_original is not None and distance_from_original <= LINK_TRANSFORM_ZERO_ORIGIN_TOLERANCE_FT)
        data["final_transform_basis_matches_original"] = _transform_basis_matches(final_transform, data.get("original_transform"))
    except Exception as final_exc:
        data["blocking_reasons"].append("Post-rollback verification failed: {0}".format(safe_str(final_exc)))
    final_distance = data.get("final_distance_from_original")
    data["persistent_model_changes"] = bool(final_distance is not None and final_distance > LINK_TRANSFORM_ZERO_ORIGIN_TOLERANCE_FT)
    data["link_transform_modified_persistently"] = bool(data.get("persistent_model_changes"))
    if data.get("rollback_test_result") != "Failed":
        if data.get("temporary_verification_passed") and data.get("transaction_group_rolled_back") and data.get("final_origin_matches_original"):
            data["rollback_test_result"] = "Passed"
        else:
            data["rollback_test_result"] = "Failed"
            if not data.get("temporary_verification_passed"):
                data["blocking_reasons"].append("Temporary origin was not zero within tolerance.")
            if not data.get("transaction_group_rolled_back"):
                data["blocking_reasons"].append("TransactionGroup was not rolled back successfully.")
            if not data.get("final_origin_matches_original"):
                data["blocking_reasons"].append("Final origin did not match original after rollback.")
    data["recommended_next_action"] = _coord_link_rollback_recommendation(data)
    return data


